import { MotoristaService, MotoristaAtivo } from '../../../servicos/motorista.service';
import { environment } from '../../../../environments/environment';
import { Subscription } from 'rxjs';

@Component({
  selector: 'app-acompanhar',
  templateUrl: './acompanhar.page.html',
  styleUrls: ['./acompanhar.page.scss'],
})
export class AcompanharPage implements OnInit, OnDestroy {
  corridaId: number = 0;
  corrida: Corrida | null = null;
  motoristasAtivos: MotoristaAtivo[] = [];
  wsSubscription?: Subscription;
  corridasSubscription?: Subscription;
  atualizacaoInterval: any;
  motoristasInterval: any;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private corridaService: CorridaService,
    private wsService: WebsocketService,
    private mockApi: ApiMockService,
    private motoristaService: MotoristaService,
    private alertCtrl: AlertController,
    private toastCtrl: ToastController
  ) {}

  ngOnInit() {
    this.corridaId = parseInt(this.route.snapshot.paramMap.get('id') || '0');
    this.carregarCorrida();
    
    if (environment.useMock) {
      // No mock, escuta mudanças no BehaviorSubject
      this.corridasSubscription = this.mockApi.corridas$.subscribe(corridas => {
        const corridaAtualizada = corridas.find(c => c.id === this.corridaId);
        if (corridaAtualizada) {
          this.corrida = corridaAtualizada;
          this.verificarMudancaEstado(corridaAtualizada.estado);
        }
      });
      
      // Polling para garantir atualização
      this.atualizacaoInterval = setInterval(() => {
        this.carregarCorrida();
      }, 2000);
      
      // Busca motoristas próximos quando está buscando
      this.carregarMotoristasProximos();
      this.motoristasInterval = setInterval(() => {
        if (this.corrida?.estado === 'buscando') {
          this.carregarMotoristasProximos();
        }
      }, 5000);
    } else {
      this.conectarWebSocket();
      this.carregarMotoristasProximos();
    }
  }

  ngOnDestroy() {
    this.wsService.desconectar();
    this.wsSubscription?.unsubscribe();
    this.corridasSubscription?.unsubscribe();
    if (this.atualizacaoInterval) {
      clearInterval(this.atualizacaoInterval);
    }
    if (this.motoristasInterval) {
      clearInterval(this.motoristasInterval);
    }
  }

  async verificarMudancaEstado(novoEstado: string) {
    if (novoEstado === 'aceita' && this.corrida?.motorista) {
      const toast = await this.toastCtrl.create({
        message: `${this.corrida.motorista.nome} aceitou sua corrida!`,
        duration: 3000,
        color: 'success',
        position: 'top'
      });
      await toast.present();
    } else if (novoEstado === 'em_andamento') {
      const toast = await this.toastCtrl.create({
        message: 'Corrida iniciada! Boa viagem!',
        duration: 3000,
        color: 'primary',
        position: 'top'
      });
      await toast.present();
    } else if (novoEstado === 'finalizada') {
      const toast = await this.toastCtrl.create({
        message: `Corrida finalizada! Valor: R$ ${this.corrida?.preco_final?.toFixed(2)}`,
        duration: 4000,
        color: 'success',
        position: 'top'
      });
      await toast.present();
    }
  }

  async carregarCorrida() {
    try {
      this.corrida = await this.corridaService.obter(this.corridaId).toPromise() || null;
    } catch (erro) {
      const toast = await this.toastCtrl.create({
        message: 'Erro ao carregar corrida',
        duration: 3000,
        color: 'danger'
      });
      await toast.present();
    }
  }

  async carregarMotoristasProximos() {
    if (!this.corrida) return;
    
    try {
      this.motoristasAtivos = await this.motoristaService.listarMotoristasAtivos(
        this.corrida.origem_lat,
        this.corrida.origem_lon,
        10 // 10km de raio
      ).toPromise() || [];
    } catch (erro) {
      console.error('Erro ao carregar motoristas:', erro);
      this.motoristasAtivos = [];
    }
  }

  conectarWebSocket() {
    this.wsService.conectar(this.corridaId);
    this.wsSubscription = this.wsService.obterMensagens().subscribe(async (msg) => {
      if (msg) {
        console.log('Atualização WS:', msg);
        await this.carregarCorrida();
      }
    });
  }

  obterTextoEstado(): string {
    const estados: any = {
      buscando: 'Procurando motorista...',
      aceita: 'Motorista a caminho',
      em_andamento: 'Corrida em andamento',
      finalizada: 'Corrida finalizada',
      cancelada: 'Corrida cancelada'
    };
    return estados[this.corrida?.estado || 'buscando'] || 'Aguardando...';
  }

  async cancelarCorrida() {
    const alert = await this.alertCtrl.create({
      header: 'Cancelar Corrida',
      message: 'Deseja realmente cancelar esta corrida?',
      buttons: [
        { text: 'Não', role: 'cancel' },
        {
          text: 'Sim',
          handler: async () => {
            try {
              await this.corridaService.cancelar(this.corridaId).toPromise();
              const toast = await this.toastCtrl.create({
                message: 'Corrida cancelada',
                duration: 2000,
                color: 'success'
              });
              await toast.present();
              this.router.navigate(['/passageiro/mapa']);
            } catch (erro) {
              const toast = await this.toastCtrl.create({
                message: 'Erro ao cancelar',
                duration: 3000,
                color: 'danger'
              });
              await toast.present();
            }
          }
        }
      ]
    });
    await alert.present();
  }

  async avaliar() {
    const alert = await this.alertCtrl.create({
      header: 'Avaliar Motorista',
      inputs: [
        { name: 'nota', type: 'number', min: 1, max: 5, placeholder: 'Nota (1-5)' },
        { name: 'comentario', type: 'textarea', placeholder: 'Comentário (opcional)' }
      ],
      buttons: [
        { text: 'Cancelar', role: 'cancel' },
        {
          text: 'Enviar',
          handler: async (data) => {
            const toast = await this.toastCtrl.create({
              message: 'Avaliação enviada!',
              duration: 2000,
              color: 'success'
            });
            await toast.present();
            this.router.navigate(['/passageiro/mapa']);
          }
        }
      ]
    });
    await alert.present();
  }
}
<ion-header>
  <ion-toolbar color="primary">
    <ion-buttons slot="start">
      <ion-back-button defaultHref="/passageiro/mapa"></ion-back-button>
    </ion-buttons>
    <ion-title>Corrida #{{ corridaId }}</ion-title>
  </ion-toolbar>
</ion-header>

<ion-content class="ion-padding">
  <!-- Mapa Google com Rastreamento em Tempo Real -->
  <app-mapa-google 
    altura="350px"
    [origemLat]="corrida?.origem_lat"
    [origemLon]="corrida?.origem_lon"
    [destinoLat]="corrida?.destino_lat"
    [destinoLon]="corrida?.destino_lon"
    [motoristaLat]="corrida?.motorista_lat"
    [motoristaLon]="corrida?.motorista_lon"
    [motoristasAtivos]="motoristasAtivos"
    [permiteArrastarOrigem]="false"
  ></app-mapa-google>

  <div class="status-container">
    <p class="status-text">{{ obterTextoEstado() }}</p>
    <p *ngIf="corrida?.estado === 'buscando' && motoristasAtivos.length > 0" class="motoristas-disponiveis">
      {{ motoristasAtivos.length }} motorista(s) disponível(is) próximo(s)
    </p>
  </div>

  <ion-card *ngIf="corrida">
    <ion-card-header>
      <ion-card-subtitle>Corrida #{{ corridaId }}</ion-card-subtitle>
      <ion-card-title>
        <ion-badge [color]="corrida.estado === 'buscando' ? 'warning' : corrida.estado === 'aceita' ? 'primary' : corrida.estado === 'em_andamento' ? 'success' : corrida.estado === 'finalizada' ? 'success' : 'danger'">
          {{ corrida.estado?.toUpperCase() }}
        </ion-badge>
      </ion-card-title>
    </ion-card-header>
    <ion-card-content>
      <ion-item lines="none" *ngIf="corrida.motorista">
        <ion-icon name="person-circle-outline" slot="start" color="primary"></ion-icon>
        <ion-label>
          <h3>{{ corrida.motorista.nome }}</h3>
          <p>{{ corrida.motorista.telefone }}</p>
          <p *ngIf="corrida.motorista.placa">Placa: {{ corrida.motorista.placa }}</p>
        </ion-label>
      </ion-item>

      <ion-item lines="none">
        <ion-icon name="radio-button-on" slot="start" color="success"></ion-icon>
        <ion-label class="ion-text-wrap">
          <p class="label-small">Origem</p>
          <p>{{ corrida.origem_endereco }}</p>
        </ion-label>
      </ion-item>

      <ion-item lines="none">
        <ion-icon name="location" slot="start" color="danger"></ion-icon>
        <ion-label class="ion-text-wrap">
          <p class="label-small">Destino</p>
          <p>{{ corrida.destino_endereco }}</p>
        </ion-label>
      </ion-item>

      <ion-item lines="none">
        <ion-icon name="speedometer-outline" slot="start"></ion-icon>
        <ion-label>
          {{ corrida.distancia_km | number:'1.1-1' }} km · {{ corrida.duracao_min | number:'1.0-0' }} min
        </ion-label>
      </ion-item>

      <ion-item lines="none">
        <ion-icon name="cash-outline" slot="start"></ion-icon>
        <ion-label>
          <p class="label-small">Preço Estimado</p>
          <h2>R$ {{ corrida.preco_estimado?.toFixed(2) }}</h2>
        </ion-label>
      </ion-item>

      <ion-item lines="none" *ngIf="corrida.preco_final">
        <ion-icon name="checkmark-circle" slot="start" color="success"></ion-icon>
        <ion-label>
          <p class="label-small">Valor Final</p>
          <h2 class="price-final">R$ {{ corrida.preco_final.toFixed(2) }}</h2>
        </ion-label>
      </ion-item>
    </ion-card-content>
  </ion-card>

  <ion-button 
    expand="block" 
    color="danger" 
    (click)="cancelarCorrida()"
    *ngIf="corrida?.estado === 'buscando' || corrida?.estado === 'aceita'"
  >
    <ion-icon name="close-circle" slot="start"></ion-icon>
    Cancelar Corrida
  </ion-button>

  <ion-button 
    expand="block" 
    color="success" 
    (click)="avaliar()"
    *ngIf="corrida?.estado === 'finalizada'"
  >
    <ion-icon name="star" slot="start"></ion-icon>
    Avaliar Motorista
  </ion-button>

  <ion-button 
    expand="block" 
    fill="outline"
    routerLink="/passageiro/mapa"
    *ngIf="corrida?.estado === 'finalizada' || corrida?.estado === 'cancelada'"
  >
    <ion-icon name="home" slot="start"></ion-icon>
    Nova Corrida
  </ion-button>
</ion-content>
